query MarketsMutationPreflightHydrate($priceListId: ID!) {
  priceList(id: $priceListId) {
    __typename
    id
    name
    currency
    fixedPricesCount
    quantityRules(first: 20) {
      edges {
        cursor
        node {
          minimum
          maximum
          increment
          isDefault
          originType
          productVariant { id }
        }
      }
    }
    prices(first: 20) {
      edges {
        cursor
        node {
          price { amount currencyCode }
          compareAtPrice { amount currencyCode }
          originType
          variant { id sku product { id title } }
          quantityPriceBreaks(first: 20) {
            edges {
              cursor
              node {
                minimumQuantity
                price { amount currencyCode }
              }
            }
          }
        }
      }
    }
  }
  products(first: 10) {
    nodes {
      id
      title
      variants(first: 20) {
        nodes { id title sku }
      }
    }
  }
}

